                new CermatTask { TaskNumber = "14", Category = TaskCategory.Ordering, MaxPoints = 3, Instruction = "Seřaďte jednotlivé části textu (A-F) tak, aby byla dodržena textová návaznost.", ExpectedSequence = new() { "D", "A", "F", "B", "E", "C" }, Options = new() { new TaskOption { Label = "A", Text = "Právě v tomto zařízení má Britt-Marie pracovat. Jednoho lednového dne proto sedne do auta a dorazí do Borgu. Ve chvíli, kdy odbočuje na parkoviště, zaslechne z útrob vozu jakýsi zvuk." }, new TaskOption { Label = "B", Text = "Britt-Marie z něj vyděšeně vyskočí, protože logicky očekává, že auto vzplane. Ale nevzplane. Opodál se poklidně kutálí míč. Když balón zmizí za rohem budovy označené nápisem DŮM DĚTÍ A MLÁDEŽE, ozve se zadunění." }, new TaskOption { Label = "C", Text = "Úplně nahoře stojí „jet do Borgu“. Tenhle bod si odškrtne. Další položka zní „vyzvednout klíče na poště“. Vytáhne mobil a poprvé v životě ho použije." }, new TaskOption { Label = "D", Text = "Borg je vesnice u silnice. To je vlastně to nejhezčí, co se o Borgu dá říct. Je tu zrušené fotbalové hřiště, zrušená škola, zrušená lékárna a zrušené potraviny. Funguje tady dům dětí a mládeže, ale to jen proto, že ho zrušit ještě nestihli." }, new TaskOption { Label = "E", Text = "Zdálky to zní, jako kdyby někdo nacpal do sušičky kamení. Není to sice příliš pravděpodobné, ale Britt-Marie už zažila leccos. Sedne si na lavičku a roztřeseně vyndá z kabelky seznam." }, new TaskOption { Label = "F", Text = "Stižena adekvátní panikou, Britt-Marie pustí spojku i brzdu. Auto zakašle, jako by se něčeho leklo, když se zrovna ládovalo popcornem. Po několika dramatických smycích na zledovatělém povrchu konečně s rachotem zastaví." } }, Explanation = "Představení Borgu (D) -> Příjezd Britt-Marie (A) -> Zastavení auta (F) -> Vyskočení z auta a míč (B) -> Zvuk a usednutí na lavičku (E) -> Odškrtnutí bodu (C)." },
