                new CermatTask { TaskNumber = "16", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících slovních hodnocení nejlépe odpovídá textu o výrobě krmítka?", TextBase = textKrmitko, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Snažil ses splnit zadaný úkol, tj. napsat popis pracovního postupu. Jednotlivé kroky na sebe logicky navazují, příště ale více promysli jazykové prostředky - v tomto typu textu není vhodné používat např. slovesa v 1. osobě čísla množného." }, new TaskOption { Label = "B", Text = "Zadaný úkol, tj. napsat subjektivně zabarvený popis předmětu, jsi splnil. Jednotlivé informace jsou logicky řazeny, příště ale více promysli jazykové prostředky - v tomto typu textu není vhodné používat např. slovesa v 1. osobě čísla množného." }, new TaskOption { Label = "C", Text = "Snažil ses splnit zadaný úkol, tj. napsat popis pracovního postupu. Vhodně jsi použil některé jazykové prostředky, např. slovesa v 1. osobě čísla množného. Příště ale více promysli popis jednotlivých kroků a jejich návaznost, protože v této oblasti tvůj text vykazuje nedostatky." }, new TaskOption { Label = "D", Text = "Zadaný úkol, tj. napsat subjektivně zabarvený popis předmětu, jsi splnil. Vhodně jsi použil některé jazykové prostředky, např. slovesa v 1. osobě čísla množného. Příště ale více promysli popis předmětu a řazení jednotlivých informací, protože v této oblasti tvůj text vykazuje nedostatky." } }, Explanation = "Je to popis pracovního postupu, slovesa v 1. os. množného čísla se zde běžně užívají, ale text má mezery v návaznosti postupu (dírky v miskách, pak svázání a náhle protahování pátou dírkou bez předchozího uvedení vrtání páté dírky)." },
                new CermatTask { TaskNumber = "17", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z tvrzení, zda jednoznačně vyplývá z TEXTU 1 (Kód horečky).", TextBase = textLeavitt, Items = new() { new SubItem { Id = "17.1", Text = "Doktor Leavitt si nahlas opakoval jednu větu, aby se uklidnil během nečekaného rozruchu na chodbě.", ExpectedAnswer = "NE" }, new SubItem { Id = "17.2", Text = "Těsně před tím, než omdlel, se Minho chystal Thomasovi prozradit, co přesně mu v nemocnici voperovali do hlavy.", ExpectedAnswer = "NE" }, new SubItem { Id = "17.3", Text = "Pacient s obvázanou hlavou reagoval křikem na anestezii, která mu byla aplikována v přítomnosti doktora Leavitta.", ExpectedAnswer = "NE" }, new SubItem { Id = "17.4", Text = "K prvnímu setkání Thomase a doktora Leavitta došlo před 8. hodinou ranní, a to tentýž den, kdy byl Thomas poprvé v devátém patře.", ExpectedAnswer = "ANO" } }, Explanation = "17.1: Větu říkal pro Thomase. 17.2: Minho říkal, že dělají 'jakoby nic, ale jsou banda prolhaných', nikoliv že mu prozradí co přesně mu voperovali. 17.3: Křičel předtím, než mu sestřička něco píchla na chodbě. 17.4: Správně, doktor zaťukal před osmou ranní ('Za půl hodiny - přesně v osm...') a hned v osm jeli do 9. patra." },
                new CermatTask { TaskNumber = "18", Category = TaskCategory.Filling, MaxPoints = 2, Instruction = "Vypište z podtržených úseků větné členy.", TextBase = textLeavitt, InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"za nimi", "monitorů"}, Explanation = "18.1: Příslovečné určení místa (Kde stojí? za nimi). 18.2: Přívlastek neshodný (Jaká světla? monitorů)." },
                new CermatTask { TaskNumber = "19", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Co patří na vynechaná místa (*****) v TEXTU 1? (Řešte na základě TEXTU 2.)", TextBase = textLeavitt, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Na každé z těchto míst patří jakoby." }, new TaskOption { Label = "B", Text = "Na každé z těchto míst patří jako by." }, new TaskOption { Label = "C", Text = "Na místo z první části textu patří jakoby, na místo ze čtvrté části textu patří jako by." }, new TaskOption { Label = "D", Text = "Na místo z první části textu patří jako by, na místo ze čtvrté části textu patří jakoby." } }, Explanation = "1. 'jeho nálada jako by se odrážela' (by je součástí podmiňovacího způsobu). 4. 'dělají jakoby nic' (jedno slovo, není to podmiňovací způsob)." },
                new CermatTask { TaskNumber = "20", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o třetí části TEXTU 1 je pravdivé?", TextBase = textLeavitt, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "V této části promlouvá jak v přímé, tak v nepřímé řeči Thomas." }, new TaskOption { Label = "B", Text = "V této části promlouvá jak v přímé, tak v nepřímé řeči jiná postava než Thomas." }, new TaskOption { Label = "C", Text = "V této části promlouvá v přímé řeči nejspíše někdo jiný než Thomas, další postava něco sděluje v nepřímé řeči." }, new TaskOption { Label = "D", Text = "V této části promlouvá v přímé řeči nejspíše někdo jiný než Thomas, žádná z postav nic nesděluje v nepřímé řeči." } }, Explanation = "Je tam pouze 'Minho, stůj!', což pravděpodobně křičely sestry. Nikdo zde nic nesděluje nepřímou řečí." },
