                new CermatTask { TaskNumber = "15", Category = TaskCategory.Ordering, MaxPoints = 3, Instruction = "Seřaďte části textu (A–F) tak, aby byla dodržena textová návaznost.", ExpectedSequence = new() { "E", "B", "D", "C", "A", "F" }, Options = new() { new TaskOption { Label = "A", Text = "Věnovala dvacet minut tomu, aby odpověděla tak, jak Borgov nečekal. Další hodiny se nedívala na něj ani na diváky, dokonce ani na rozhodčího ne.Sledovala pouze ztělesněné hrozby – jezdce, střelce, věž, pěšce, krále a dámu." }, new TaskOption { Label = "B", Text = "Už seděl u stolu a čekal na ni. Při tom pohledu se mladé ženě zastavilo srdce i dech: ta nehybná postava, upřeně pozorující černé figurky v základním postavení, nejevila žádné známky slabosti." }, new TaskOption { Label = "C", Text = "Zahájila pěšcem na d4 a soustředila se na šachovnici. V hlavě měla jasno a tahy znala. Sedmým tahem ji ovšem Borgov překvapil." }, new TaskOption { Label = "D", Text = "Beth pomalu došla k šachovnici a usadila se k bílým. Z obecenstva se ozval tichý potlesk. Rozhodčí zmáčkl knoflík a Beth uslyšela, jak se jí rozběhly hodiny" }, new TaskOption { Label = "E", Text = "Když Beth přecházela jeviště, všimla si, že hlediště je úplně napěchované. Pak se ten obrovský dav ztišil a ona se poprvé podívala na Borgova. Měla z něj hrůzu od té doby, co ho spatřila před gorilí klecí během turnaje v Mexiku." }, new TaskOption { Label = "F", Text = "Když Borgovovi zbývalo posledních sedm minut, rozhodl se, že nechá svůj tah zapečetit. Pokračovat v rozehrané partii se bude následující den ráno." } }, Explanation = "Správné pořadí: Příchod (E) -> Pohled na Borgova u stolu (B) -> Usednutí a start hodin (D) -> Zahájení partie (C) -> Průběh partie (A) -> Konec a zapečetění tahu (F)." },
                new CermatTask { TaskNumber = "16", Category = TaskCategory.Correction, MaxPoints = 4, Instruction = "Najděte 4 slova zapsaná s pravopisnou chybou a napište je SPRÁVNĚ.", TextBase = textPisek, InputFieldsCount = 4, UserInputs = new string[] { "", "", "", "" }, ExpectedSequence = new() { "kamenný", "zprostředkují", "včelí", "náramně" }, Explanation = "Kamenný (kamen+ný), zprostředkují (předpona z-), včelí (vzor jarní), náramně (náramný+ně)." },
