                new CermatTask { TaskNumber = "5", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení je pravdivé? (Slova NEUSTÁLE a NEDALEKO jsou v TEXTU 1 zapsána velkými písmeny.)", TextBase = textDublin, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Slova neustále a stále jsou v kontextu TEXTU 1 antonymy, totéž platí i pro slova nedaleko a daleko." }, new TaskOption { Label = "B", Text = "Slova neustále a stále nejsou v kontextu TEXTU 1 antonymy, totéž platí i pro slova nedaleko a daleko." }, new TaskOption { Label = "C", Text = "Slova neustále a stále jsou v kontextu TEXTU 1 antonymy, slova nedaleko a daleko v kontextu tohoto textu antonymy nejsou." }, new TaskOption { Label = "D", Text = "Slova neustále a stále nejsou v kontextu TEXTU 1 antonymy, slova nedaleko a daleko v kontextu tohoto textu antonymy jsou." } }, Explanation = "Slova neustále a stále znamenají to samé (jsou synonyma). Slova nedaleko a daleko znamenají opak (jsou antonyma)." },
                new CermatTask { TaskNumber = "6", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Na první vynechané místo [ ***** ] v TEXTU 1 patří správné jméno spisovatele a na druhé vynechané místo [ ..... ] v TEXTU 1 patří správný název literárního díla. Ve které z následujících možností jsou uvedeny obě tyto chybějící informace?", TextBase = textDublin, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Homér – Ilias" }, new TaskOption { Label = "B", Text = "Sofokles – Oidipus král" }, new TaskOption { Label = "C", Text = "James Joyce – Odysseus" }, new TaskOption { Label = "D", Text = "Albert Camus – Mýtus o Sisyfovi" } }, Explanation = "Autor využívající metodu 'proud vědomí' pocházející z Irska (Dublin) s hrdinou Leopoldem Bloomem je James Joyce a jeho román se jmenuje Odysseus." },
                new CermatTask { TaskNumber = "7", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících vět není zapsána pravopisně správně?", ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "Zaměstnanec recepce mi na dotaz odpověděl velmi nedútklivým tónem." }, new TaskOption { Label = "B", Text = "Této mezinárodní konference se zúčastnily skoro všechny evropské státy." }, new TaskOption { Label = "C", Text = "První neděli v měsíci pravidelně chodí do kosmetického studia na manikúru." }, new TaskOption { Label = "D", Text = "Jejich žádost o poskytnutí bezúročné půjčky byla bankou okamžitě zamítnuta." } }, Explanation = "Slovo 'nedútklivý' je napsáno špatně. Správně má být s kroužkem: 'nedůtklivý' (nemá to nic společného se začátkem slova či předponou ú-, kořen je tkl/tkývat, dříve dotýkat, tedy ne-dů-tklivý)." },
                new CermatTask { TaskNumber = "8", Category = TaskCategory.Ordering, MaxPoints = 3, Instruction = "Seřaďte jednotlivé části textu (A–E) tak, aby byla dodržena textová návaznost (K. Čapek, Válka s Mloky).", TextBase = textMloky, ExpectedSequence = new() { "D", "B", "E", "A", "C" }, Options = new() { new TaskOption { Label = "A", Text = "Mlok ho vzal do tlapky a počal ho okusovat. „Koukej, mlok,“ chrochtalo zvířátko spokojeně a pokukovalo po Greggsovi, „tati, ten je škaredý!“ Aha, řekl si Greggs, on opakuje, co slyší od lidí. „Pověz, jak se jmenuju,“ zkusil to." }, new TaskOption { Label = "B", Text = "Ohlédl se, ale nikdo tam nebyl. Něco se mi zdálo, mínil pan Greggs a zametal. „Koukej, mlok,“ ozval se zase za ním čísi hlas. Greggs se rychle otočil." }, new TaskOption { Label = "C", Text = "„Pan Thomas Greggs. Dobrý den, pane.“ Zdálo se, že se mlok nemůže řeči nabažit. Greggs ale už nevěděl, co by mu povídal, a navíc měl dost práce, takže rozhovor ukončil: „Tak, a teď drž hubu. Až budu hotov, budu tě učit mluvit.“" }, new TaskOption { Label = "D", Text = "Pan Greggs, hlídač v pavilonu obojživelníků, uklízel a čistil nádrže svých svěřenců. Zoo byla dnes obecenstvu uzavřena a on si užíval ticha a samoty v oddílu, kde byl vystaven velký mlok Andrias Scheuchzeri a množství dalších čolků a mločíků. Zničehonic se za ním ozvalo skřehotavě: „Koukej, mami.“" }, new TaskOption { Label = "E", Text = "Andrias stál přímo za ním a díval se na něho, mrkaje spodními víčky. „Ty... ty umíš mluvit?“ koktal pan Greggs. „Dobrý den,“ zaskřehotal mlok. „Smím mu dát koláč?“ Pan Greggs sáhl zmateně do kapsy a vytáhl rohlík. „Na, tumáš.“" } }, Explanation = "Představení situace, Greggs uklízí a slyší hlas (D). Ohlédne se, nikdo tam není, slyší další hlas a otočí se (B). Zjistí, že to mluví mlok a dá mu jídlo (E). Mlok jí a něco poví, Greggs to zkusí: 'Pověz, jak se jmenuju' (A). Mlok odpoví jménem a rozhovor končí (C)." },
                new CermatTask { TaskNumber = "9", Category = TaskCategory.Matching, MaxPoints = 3, Instruction = "Přiřaďte k jednotlivým tvrzením (9.1–9.3) odpovídající souvětí (A–E).", Items = new() { new SubItem { Id = "9.1", Text = "Pomocí spojovacího výrazu je v souvětí vyjádřeno, že význam druhé věty vyplývá z významu první věty jako její důsledek.", ExpectedAnswer = "D" }, new SubItem { Id = "9.2", Text = "Pomocí spojovacího výrazu je v souvětí vyjádřeno, že význam druhé věty je pokládán za silnější nebo závažnější, než je význam první věty.", ExpectedAnswer = "B" }, new SubItem { Id = "9.3", Text = "Pomocí spojovacího výrazu je v souvětí vyjádřeno, že význam první věty a význam druhé věty nemohou platit oba zároveň – může platit pouze jeden.", ExpectedAnswer = "C" } }, Options = new() { new TaskOption { Label = "A", Text = "Občas se dokázal pořádně rozčílit, obvykle však reagoval klidně." }, new TaskOption { Label = "B", Text = "Včera večer vůbec nepřišel domů, ani mi dokonce nezvedal telefon." }, new TaskOption { Label = "C", Text = "Buď přijede za chvíli přímým autobusem, nebo dorazí později vlakem." }, new TaskOption { Label = "D", Text = "V testu jsem zvládl většinu úloh, zkoušku tudíž nebudu muset opakovat." }, new TaskOption { Label = "E", Text = "Tenhle detail jsem minule vynechal, neboť jsem si na něj tehdy nevzpomněl." } }, Explanation = "9.1 = poměr důsledkový ('tudíž', věta D). 9.2 = poměr stupňovací ('ani dokonce', věta B). 9.3 = poměr vylučovací ('buď - nebo', věta C)." },
                new CermatTask { TaskNumber = "10", Category = TaskCategory.Filling, MaxPoints = 1, Instruction = "Vypište z první sloky TEXTU 1 podstatné jméno a sloveso, které jsou příbuzné. (Zapište ve stejném tvaru jako v textu).", TextBase = textSlezske, InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"žil", "životě"}, Explanation = "V textu se nachází sloveso 'žil' (Žil jsem jak stepní kůň...) a podstatné jméno 'životě' (...v životě prostém). Sdílí stejný kořen (živ-)." },
                new CermatTask { TaskNumber = "11", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení odpovídá TEXTU 1?", TextBase = textSlezske, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Lyrický subjekt sděluje, že hudba, jíž se kdysi věnoval, byla zasvěcena bohům." }, new TaskOption { Label = "B", Text = "Lyrický subjekt přiznává, že polovinu svého života trpěl závislostí na alkoholu." }, new TaskOption { Label = "C", Text = "Lyrický subjekt sděluje, že s tím, odkud pochází, souvisí způsob jeho vyjadřování." }, new TaskOption { Label = "D", Text = "Lyrický subjekt přiznává, že se cítí svobodněji v přítomnosti koní než mezi lidmi." } }, Explanation = "Lyrický subjekt v závěru básně říká: 'byl jsem... ze Slezské, jinak jsem neuměl mluvit' – původ determinuje způsob jeho vyjadřování." },
                new CermatTask { TaskNumber = "12", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících možností vystihuje TEXT 1?", TextBase = textSlezske, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "Báseň je psána volným veršem, rýmové schéma odpovídá rýmu střídavému." }, new TaskOption { Label = "B", Text = "Báseň není psána volným veršem, rýmové schéma odpovídá rýmu střídavému." }, new TaskOption { Label = "C", Text = "Báseň je psána volným veršem, rýmové schéma neodpovídá rýmu střídavému." }, new TaskOption { Label = "D", Text = "Báseň není psána volným veršem, rýmové schéma neodpovídá rýmu střídavému." } }, Explanation = "Báseň není volným veršem (verše jsou metricky uspořádané) a schéma je svobody-vody (a), prostém-mostem (b), tedy a-b-a-b, což je střídavý rým." },
                new CermatTask { TaskNumber = "13", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Na vynechané místo [ ***** ] v TEXTU 2 patří jméno básníka, jemuž je obvykle připisováno autorství sbírky Slezské písně (1909). O které z následujících jmen jde?", TextBase = textSlezske, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Nerudo Jane" }, new TaskOption { Label = "B", Text = "Viktore Dyku" }, new TaskOption { Label = "C", Text = "Bezruči Petře" }, new TaskOption { Label = "D", Text = "Františku Šrámku" } }, Explanation = "Sbírku Slezské písně napsal Petr Bezruč." },
                new CermatTask { TaskNumber = "14", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Jak by bylo třeba upravit úsek podtržený ve výchozím textu, aby bylo i bez dalšího kontextu zcela jednoznačné, že slovo INFORMACE je v tomto úseku užito v množném čísle?", TextBase = textFairtrade, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "místo slova aktuální napsat slovo nejnovější" }, new TaskOption { Label = "B", Text = "těsně před slovo aktuální napsat slovo důležité" }, new TaskOption { Label = "C", Text = "místo slova situaci napsat slovo poměrech" }, new TaskOption { Label = "D", Text = "těsně před slovo situaci napsat slovo skutečné" } }, Explanation = "Pokud napíšeme 'důležité aktuální informace', tvar přídavného jména 'důležité' je typický pro množné číslo (v jednotném čísle by to byla 'důležitá informace'). Tím se množné číslo stane jednoznačným." },
                new CermatTask { TaskNumber = "15", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících tvrzení, zda jednoznačně vyplývá z výchozího textu (Fairtrade).", TextBase = textFairtrade, Items = new() { new SubItem { Id = "15.1", Text = "Výrobní družstva zapojená do systému fairtrade sdružují bezmála dva miliony drobných producentů z desítek různých zemí.", ExpectedAnswer = "ANO" }, new SubItem { Id = "15.2", Text = "Jedním z hlavních cílů systému fairtrade je zajistit, aby africké, jihoamerické a asijské země co možná nejdříve uzákonily vyšší minimální mzdu.", ExpectedAnswer = "NE" }, new SubItem { Id = "15.3", Text = "Cena výrobků se známkou FAIRTRADE je obvykle vyšší než cena běžného zboží především kvůli nákladům na šíření osvěty mezi spotřebitele.", ExpectedAnswer = "NE" }, new SubItem { Id = "15.4", Text = "Přibližně 70 % ze všech výrobků nabízených na světovém trhu tvoří potraviny, které jsou vyrobeny v souladu se standardy systému fairtrade.", ExpectedAnswer = "NE" } }, Explanation = "15.1 Ano (téměř 2 miliony z více než 70 zemí - což jsou desítky). 15.2 Ne (systém to řeší na své úrovni certifikací, netlačí nutně na uzákonění ze strany států jako svůj primární nástroj). 15.3 Ne (text to dává do souvislosti s péčí o výrobce a osvětou). 15.4 Ne (70% Z FAIRTRADOVÝCH výrobků jsou potraviny, nikoli 70% VŠECH výrobků na světovém trhu)." },
                new CermatTask { TaskNumber = "16", Category = TaskCategory.Filling, MaxPoints = 2, Instruction = "Vypište z první části výchozího textu: 16.1 sloveso užité v rozkazovacím způsobu, 16.2 sloveso užité v podmiňovacím způsobu.", TextBase = textFairtrade, InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"mějme", "získali bychom"}, Explanation = "1. Mějme (rozkazovací způsob 1. osoby mn. čísla). 2. Získali bychom (podmiňovací způsob přítomný)." },
                new CermatTask { TaskNumber = "17", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Kterou z následujících možností je nutné doplnit na vynechané místo [ ***** ] v druhé části výchozího textu, aby byl větný celek smysluplný a gramaticky správný?", TextBase = textFairtrade, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "musí mít zasvé" }, new TaskOption { Label = "B", Text = "musí vzít zavděk" }, new TaskOption { Label = "C", Text = "nesmí mít zasvé" }, new TaskOption { Label = "D", Text = "nesmí vzít zavděk" } }, Explanation = "Zkontextu vyplývá, že výrobce nemá na výběr a musí přijmout (vzít zavděk) nabídnutou částku od překupníků, i když je nevýhodná." },
                new CermatTask { TaskNumber = "18", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o zájmenu, jež patří na vynechané místo [ ..... ] ve třetí části výchozího textu, je pravdivé?", TextBase = textFairtrade, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "Tímto zájmenem je rozvit větný člen věcí, náležitý tvar zájmena je tedy jejichž." }, new TaskOption { Label = "B", Text = "Tímto zájmenem je rozvit větný člen snaha, náležitý tvar zájmena je tedy jejímž." }, new TaskOption { Label = "C", Text = "Tímto zájmenem je rozvit větný člen podmínek, náležitý tvar zájmena je tedy jejichž." }, new TaskOption { Label = "D", Text = "Tímto zájmenem je rozvit větný člen produkce, náležitý tvar zájmena je tedy jejímž." } }, Explanation = "Jde o snahu o zlepšení... (jakou snahu?), JEJÍMŽ příkladem je hnutí fairtrade." },
                new CermatTask { TaskNumber = "19", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících možností vystihuje úsek tučně vyznačený ve výchozím textu?", TextBase = textFairtrade, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Jak informace, že jsou fairtradové výrobky dražší než běžné zboží, tak informace, proč roste zájem o fairtradové výrobky, jsou zde předkládány jako objektivní fakt." }, new TaskOption { Label = "B", Text = "Ani informace, že jsou fairtradové výrobky dražší než běžné zboží, ani informace, proč roste zájem o fairtradové výrobky, zde není předkládána jako objektivní fakt." }, new TaskOption { Label = "C", Text = "Informace, že jsou fairtradové výrobky dražší než běžné zboží, je zde předkládána jako objektivní fakt, avšak informace, proč roste zájem o fairtradové výrobky, nikoli." }, new TaskOption { Label = "D", Text = "Informace, proč roste zájem o fairtradové výrobky, je zde předkládána jako objektivní fakt, avšak informace, že jsou fairtradové výrobky dražší než běžné zboží, nikoli." } }, Explanation = "To, že jsou výrobky dražší, je fakt. Ale proč roste zájem je uvedeno slovy 'možná právě proto' – což představuje spekulaci/domněnku, nikoli stoprocentní fakt." },
                new CermatTask { TaskNumber = "20", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících větných celků, zda je zapsán pravopisně SPRÁVNĚ.", Items = new() { new SubItem { Id = "20.1", Text = "V alchymistické expozici jsem mezi dvěma přístroji s olověnými trubičkami zahlédl staré dvouramenné váhy.", ExpectedAnswer = "ANO" }, new SubItem { Id = "20.2", Text = "Mnozí lidé prý ještě dnes věří, že by své mobily měli vždy nechat úplně vybít, aby se nezkracovala výdrž baterie.", ExpectedAnswer = "ANO" }, new SubItem { Id = "20.3", Text = "Dotčené instituce si byly vědomy závažných pochybení, porušování zákonných postupů na pracovišti ale nezabránily.", ExpectedAnswer = "ANO" }, new SubItem { Id = "20.4", Text = "Zastupitelé nemohli schválit tento návrh, protože na danném místě bude již brzy zahájena výstavba nového dětského hřiště.", ExpectedAnswer = "NE" } }, Explanation = "V poslední větě je pravopisná chyba: má být 'na daném místě' (od slovesa dát), nikoliv 'danném'." },
                new CermatTask { TaskNumber = "21", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve kterém z následujících slov je jádrem jedné ze slabik slabikotvorná souhláska? (Řešte na základě výchozího textu).", TextBase = textSlabika, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "zapšklý" }, new TaskOption { Label = "B", Text = "zatrpklý" }, new TaskOption { Label = "C", Text = "nezkrotný" }, new TaskOption { Label = "D", Text = "nevzhledný" } }, Explanation = "Ve slově za-trp-klý tvoří druhou slabiku 'trp', kde není žádná samohláska, jádrem je zde slabikotvorné 'r'." },
                new CermatTask { TaskNumber = "22", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o úseku podtrženém ve výchozím textu je pravdivé?", TextBase = textRybiKrev, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Úsek je součástí Olininy přímé řeči, adresované Hance." }, new TaskOption { Label = "B", Text = "Úsek je součástí Hančiny přímé řeči, adresované Petrovi." }, new TaskOption { Label = "C", Text = "Úsek je součástí Petrovy přímé řeči a obsahuje reprodukovanou promluvu Hanky." }, new TaskOption { Label = "D", Text = "Úsek je součástí Petrovy přímé řeči a obsahuje reprodukovanou promluvu Oliny." } }, Explanation = "Mluví Petr (k Hance) a doslova říká: 'Olina mi posledně říkala, že máš psací stroj.' Reprodukuje tak v nepřímé řeči výrok Oliny." },
                new CermatTask { TaskNumber = "23", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících tvrzení, zda jednoznačně vyplývá z výchozího textu (Rybí krev).", TextBase = textRybiKrev, Items = new() { new SubItem { Id = "23.1", Text = "Hanka se domnívá, že Venca se i za současných okolností chová lhostejně, protože je už mnoho let rozvedený.", ExpectedAnswer = "NE" }, new SubItem { Id = "23.2", Text = "Hančina vesnice náleží stejně jako Petrova k pěti obcím, které budou zcela zlikvidovány v souvislosti s novou elektrárnou.", ExpectedAnswer = "NE" }, new SubItem { Id = "23.3", Text = "Kvůli návštěvě dívek s peticí přerušila Hančina babička svou péči o záhony, jíž se pravidelně věnuje každé pondělí odpoledne.", ExpectedAnswer = "NE" }, new SubItem { Id = "23.4", Text = "Petici proti demolici chalup přinesly k Vencovým vrátkům dvě dívky, jejichž domy také leží na místech, která má zaplavit přehrada.", ExpectedAnswer = "ANO" } }, Explanation = "23.1 Ne (byl starý mládenec, nikdy nebyl ženatý). 23.2 Ne (Hančina ves bude zaplavena přehradou, část Petrovy vsi zůstane nedotčena a nepatří mezi těch 5 zcela zbouraných). 23.4 Ano (Olina a Anna stály u vrátek, a z textu víme, že chalupy Oliny a Anny skončí pod vodou)." },
                new CermatTask { TaskNumber = "24", Category = TaskCategory.Filling, MaxPoints = 2, Instruction = "Vypište: 24.1 z první části výchozího textu dvě číslovky, které jsou v tomto textu synonymy; 24.2 ze třetí části výchozího textu dvě příslovce, která jsou v tomto textu synonymy. (Zapište jako seznam oddělený čárkou).", TextBase = textRybiKrev, InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"několika, pár", "kompletně, úplně"}, Explanation = "V první části najdeme číslovky 'několika' a 'pár' s podobným významem menšího množství. Ve třetí části najdeme příslovce 'kompletně' (do háje) a 'úplně' (z mapy)." },
                new CermatTask { TaskNumber = "25", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve kterém z následujících úseků, tučně vyznačených ve výchozím textu, je každé z podstatných jmen užito v jiném pádě?", TextBase = textRybiKrev, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "rozložila jsem na podlahu papíry" }, new TaskOption { Label = "B", Text = "podepsat petici proti demolici" }, new TaskOption { Label = "C", Text = "v naprostým klidu leží na kanapi" }, new TaskOption { Label = "D", Text = "kvůli silnici vedoucí k elektrárně" } }, Explanation = "V béčku: podepsat 'petici' (4. pád - koho co), proti 'demolici' (3. pád - proti komu čemu). V ostatních možnostech jsou vždy pády shodné." },
                new CermatTask { TaskNumber = "26", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve kterém z následujících úseků výchozího textu se nevyskytuje nespisovný tvar slova?", TextBase = textRybiKrev, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "jsme stály za vrátkama jako trubky" }, new TaskOption { Label = "B", Text = "některý chalupy v okolí už zbourali" }, new TaskOption { Label = "C", Text = "tvýho strejdu chtěj vyhnat z baráku" }, new TaskOption { Label = "D", Text = "něco chystáme s jedním mým známým" } }, Explanation = "Úsek D jako jediný neobsahuje hovorové či nespisovné koncovky (A: vrátkama, B: některý místo některé, C: tvýho, chtěj, baráku)." },
